CREATE TYPE "ProblemStatus" AS ENUM ('UNVERIFIED','LEARNING','VERIFIED','MASTERED');
CREATE TYPE "Outcome" AS ENUM ('SUCCESS','PARTIAL','FAILURE');
CREATE TYPE "Difficulty" AS ENUM ('EASY','MEDIUM','HARD','UNKNOWN');
CREATE TABLE "Competency" ("id" TEXT PRIMARY KEY,"name" TEXT NOT NULL,"group" TEXT NOT NULL,"description" TEXT NOT NULL,"prerequisites" TEXT[] NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Problem" ("id" INTEGER PRIMARY KEY,"name" TEXT NOT NULL,"filePath" TEXT NOT NULL UNIQUE,"difficulty" "Difficulty" NOT NULL DEFAULT 'UNKNOWN',"status" "ProblemStatus" NOT NULL DEFAULT 'UNVERIFIED',"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL);
CREATE TABLE "ProblemCompetency" ("problemId" INTEGER NOT NULL,"competencyId" TEXT NOT NULL,"weight" DOUBLE PRECISION NOT NULL DEFAULT 1,PRIMARY KEY("problemId","competencyId"),FOREIGN KEY("problemId") REFERENCES "Problem"("id") ON DELETE CASCADE,FOREIGN KEY("competencyId") REFERENCES "Competency"("id") ON DELETE CASCADE);
CREATE TABLE "Attempt" ("id" TEXT PRIMARY KEY,"problemId" INTEGER NOT NULL,"occurredAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"outcome" "Outcome" NOT NULL,"durationMinutes" INTEGER NOT NULL,"usedHint" BOOLEAN NOT NULL DEFAULT false,"usedSolution" BOOLEAN NOT NULL DEFAULT false,"implementationCorrect" BOOLEAN NOT NULL DEFAULT false,"complexityCorrect" BOOLEAN NOT NULL DEFAULT false,"edgeCasesCorrect" BOOLEAN NOT NULL DEFAULT false,"explanationPattern" BOOLEAN NOT NULL DEFAULT false,"explanationInvariant" BOOLEAN NOT NULL DEFAULT false,"explanationAlternative" BOOLEAN NOT NULL DEFAULT false,"explanationEdgeCase" BOOLEAN NOT NULL DEFAULT false,"complexity" TEXT,"notes" TEXT,FOREIGN KEY("problemId") REFERENCES "Problem"("id"));
CREATE TABLE "ErrorTag" ("id" TEXT PRIMARY KEY,"name" TEXT NOT NULL);
CREATE TABLE "AttemptErrorTag" ("attemptId" TEXT NOT NULL,"errorTagId" TEXT NOT NULL,PRIMARY KEY("attemptId","errorTagId"),FOREIGN KEY("attemptId") REFERENCES "Attempt"("id") ON DELETE CASCADE,FOREIGN KEY("errorTagId") REFERENCES "ErrorTag"("id"));
CREATE TABLE "Review" ("id" TEXT PRIMARY KEY,"problemId" INTEGER NOT NULL,"dueAt" TIMESTAMP(3) NOT NULL,"intervalIndex" INTEGER NOT NULL DEFAULT 0,"completedAt" TIMESTAMP(3),"outcome" "Outcome","independent" BOOLEAN,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY("problemId") REFERENCES "Problem"("id"));
CREATE TABLE "Challenge" ("id" TEXT PRIMARY KEY,"title" TEXT NOT NULL,"description" TEXT NOT NULL,"competencyId" TEXT NOT NULL,"mixedCompetencies" TEXT[] NOT NULL,FOREIGN KEY("competencyId") REFERENCES "Competency"("id"));
CREATE TABLE "ChallengeAttempt" ("id" TEXT PRIMARY KEY,"challengeId" TEXT NOT NULL,"outcome" "Outcome" NOT NULL,"usedHint" BOOLEAN NOT NULL DEFAULT false,"reflection" TEXT,"occurredAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY("challengeId") REFERENCES "Challenge"("id"));
CREATE TABLE "StudySession" ("id" TEXT PRIMARY KEY,"startedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"durationMinutes" INTEGER NOT NULL,"task" TEXT NOT NULL,"predictedConfidence" INTEGER NOT NULL,"outcome" "Outcome" NOT NULL,"reflection" TEXT);
CREATE TABLE "ScoreSnapshot" ("id" TEXT PRIMARY KEY,"competencyId" TEXT NOT NULL,"score" INTEGER NOT NULL,"breadth" INTEGER NOT NULL,"retrieval" INTEGER NOT NULL,"independence" INTEGER NOT NULL,"transfer" INTEGER NOT NULL,"explanation" INTEGER NOT NULL,"reason" TEXT NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,FOREIGN KEY("competencyId") REFERENCES "Competency"("id"));
CREATE INDEX "ScoreSnapshot_competencyId_createdAt_idx" ON "ScoreSnapshot"("competencyId","createdAt");
